using UnityEngine;

namespace PasserCard.Cards
{
    /// <summary>
    /// Static card template authored as a ScriptableObject asset.
    /// </summary>
    [CreateAssetMenu(fileName = "NewCard", menuName = "PasserCard/Card Definition")]
    public class CardDefinition : ScriptableObject
    {
        [SerializeField] private string cardId = string.Empty;
        [SerializeField] private string displayName = "New Card";
        [TextArea(2, 6)]
        [SerializeField] private string description = string.Empty;
        [SerializeField] private int cost;
        [SerializeField] private int attack;
        [SerializeField] private int health;
        [SerializeField] private Sprite artwork;

        public string CardId => cardId;
        public string DisplayName => displayName;
        public string Description => description;
        public int Cost => cost;
        public int Attack => attack;
        public int Health => health;
        public Sprite Artwork => artwork;
    }
}

using System;

namespace PasserCard.Cards
{
    /// <summary>
    /// Runtime instance of a card in play (hand, deck, board, etc.).
    /// </summary>
    [Serializable]
    public sealed class CardInstance
    {
        public CardInstance(CardDefinition definition, Guid instanceId)
        {
            Definition = definition ?? throw new ArgumentNullException(nameof(definition));
            InstanceId = instanceId == Guid.Empty ? Guid.NewGuid() : instanceId;
            CurrentHealth = definition.Health;
        }

        public CardDefinition Definition { get; }
        public Guid InstanceId { get; }
        public int CurrentHealth { get; private set; }

        public string DisplayName => Definition.DisplayName;
        public int Cost => Definition.Cost;
        public int Attack => Definition.Attack;

        public void TakeDamage(int amount)
        {
            if (amount <= 0)
            {
                return;
            }

            CurrentHealth = Math.Max(0, CurrentHealth - amount);
        }

        public bool IsDestroyed => CurrentHealth <= 0;
    }
}

using System;
using System.Collections.Generic;
using PasserCard.Cards;

namespace PasserCard.Gameplay
{
    /// <summary>
    /// Ordered pile of cards with draw and shuffle support.
    /// </summary>
    public sealed class Deck
    {
        private readonly List<CardInstance> _cards = new();
        private readonly Random _random = new();

        public IReadOnlyList<CardInstance> Cards => _cards;
        public int Count => _cards.Count;

        public void Add(CardInstance card)
        {
            if (card == null)
            {
                throw new ArgumentNullException(nameof(card));
            }

            _cards.Add(card);
        }

        public void AddRange(IEnumerable<CardInstance> cards)
        {
            if (cards == null)
            {
                throw new ArgumentNullException(nameof(cards));
            }

            foreach (var card in cards)
            {
                Add(card);
            }
        }

        public void Shuffle()
        {
            for (var i = _cards.Count - 1; i > 0; i--)
            {
                var j = _random.Next(i + 1);
                (_cards[i], _cards[j]) = (_cards[j], _cards[i]);
            }
        }

        public bool TryDraw(out CardInstance card)
        {
            if (_cards.Count == 0)
            {
                card = null!;
                return false;
            }

            var lastIndex = _cards.Count - 1;
            card = _cards[lastIndex];
            _cards.RemoveAt(lastIndex);
            return true;
        }

        public void Clear() => _cards.Clear();
    }
}

