namespace PasserCard.Gameplay
{
    /// <summary>
    /// Player hand with a configurable maximum size.
    /// </summary>
    public sealed class Hand
    {
        private readonly List<CardInstance> _cards = new();

        public Hand(int maxSize = 10)
        {
            if (maxSize <= 0)
            {
                throw new ArgumentOutOfRangeException(nameof(maxSize));
            }

            MaxSize = maxSize;
        }

        public int MaxSize { get; }
        public IReadOnlyList<CardInstance> Cards => _cards;
        public int Count => _cards.Count;
        public bool IsFull => _cards.Count >= MaxSize;

        public bool TryAdd(CardInstance card)
        {
            if (card == null || IsFull)
            {
                return false;
            }

            _cards.Add(card);
            return true;
        }

        public bool TryRemove(Guid instanceId, out CardInstance card)
        {
            for (var i = 0; i < _cards.Count; i++)
            {
                if (_cards[i].InstanceId != instanceId)
                {
                    continue;
                }

                card = _cards[i];
                _cards.RemoveAt(i);
                return true;
            }

            card = null!;
            return false;
        }

        public void Clear() => _cards.Clear();
    }
}

