namespace PasserCard.Core
{
    /// <summary>
    /// Entry point MonoBehaviour. Attach to a scene object to bootstrap a match.
    /// </summary>
    public sealed class GameBootstrap : MonoBehaviour
    {
        [SerializeField] private CardDefinition[] starterDeck = System.Array.Empty<CardDefinition>();
        [SerializeField] private int openingHandSize = 5;

        private Deck _deck = new();
        private Hand _hand = new();

        public Deck Deck => _deck;
        public Hand Hand => _hand;

        private void Awake()
        {
            BuildDeck();
            DrawOpeningHand();
        }

        private void BuildDeck()
        {
            _deck.Clear();

            foreach (var definition in starterDeck)
            {
                if (definition == null)
                {
                    continue;
                }

                _deck.Add(new CardInstance(definition, System.Guid.NewGuid()));
            }

            _deck.Shuffle();
        }

        private void DrawOpeningHand()
        {
            _hand.Clear();

            for (var i = 0; i < openingHandSize; i++)
            {
                if (!_deck.TryDraw(out var card))
                {
                    break;
                }

                if (!_hand.TryAdd(card))
                {
                    break;
                }
            }
        }
    }
}

namespace PasserCard.Cards
{
    public enum Suit
    {
        Spades = 0,
        Hearts = 1,
        Clubs = 2,
        Diamonds = 3
    }

    public enum PlagueSuit
    {
        None = 0,
        CorruptSpring = 1,
        FesterBlood = 2,
        WitherBlight = 3,
        RustRot = 4
    }

    public static class SuitExtensions
    {
        public static PlagueSuit ToPlagueVariant(this Suit suit) =>
            suit switch
            {
                Suit.Spades => PlagueSuit.CorruptSpring,
                Suit.Hearts => PlagueSuit.FesterBlood,
                Suit.Clubs => PlagueSuit.WitherBlight,
                Suit.Diamonds => PlagueSuit.RustRot,
                _ => PlagueSuit.None
            };

        public static Suit FromPlagueVariant(PlagueSuit plague) =>
            plague switch
            {
                PlagueSuit.CorruptSpring => Suit.Spades,
                PlagueSuit.FesterBlood => Suit.Hearts,
                PlagueSuit.WitherBlight => Suit.Clubs,
                PlagueSuit.RustRot => Suit.Diamonds,
                _ => Suit.Spades
            };
    }
}

namespace PasserCard.Cards
{
    public enum Rank
    {
        Two = 2,
        Three = 3,
        Four = 4,
        Five = 5,
        Six = 6,
        Seven = 7,
        Eight = 8,
        Nine = 9,
        Ten = 10,
        Jack = 11,
        Queen = 12,
        King = 13,
        Ace = 14
    }

    public static class RankExtensions
    {
        public static Rank ClampRank(int value)
        {
            if (value <= (int)Rank.Two)
            {
                return Rank.Two;
            }

            if (value >= (int)Rank.Ace)
            {
                return Rank.Ace;
            }

            return (Rank)value;
        }

        public static int ToSortValue(this Rank rank) => (int)rank;
    }
}

