namespace PasserCard.Cards
{
    [Serializable]
    public sealed class PlayingCardInstance
    {
        public PlayingCardInstance(
            Guid instanceId,
            Suit suit,
            Rank cornerA,
            Rank cornerB,
            bool isFlipped = false,
            PlagueSuit plagueSuit = PlagueSuit.None)
        {
            InstanceId = instanceId == Guid.Empty ? Guid.NewGuid() : instanceId;
            Suit = suit;
            CornerA = cornerA;
            CornerB = cornerB;
            IsFlipped = isFlipped;
            PlagueSuit = plagueSuit;
        }

        public Guid InstanceId { get; }
        public Suit Suit { get; private set; }
        public Rank CornerA { get; private set; }
        public Rank CornerB { get; private set; }
        public bool IsFlipped { get; private set; }
        public PlagueSuit PlagueSuit { get; private set; }

        public bool WasPassedThisQuota { get; set; }
        public bool IsPinnedToFogSlot { get; set; }
        public bool PassEffectsSuppressed { get; set; }

        public Rank EffectiveRank => IsFlipped ? CornerB : CornerA;

        public bool IsPlagued => PlagueSuit != PlagueSuit.None;

        public void TogglePassFace() => IsFlipped = !IsFlipped;

        public void SetFace(bool useCornerB) => IsFlipped = useCornerB;

        public void ApplyPlagueSuit(PlagueSuit plague)
        {
            PlagueSuit = plague;
            if (plague != PlagueSuit.None)
            {
                Suit = SuitExtensions.FromPlagueVariant(plague);
            }
        }

        public void ResetQuotaFlags()
        {
            WasPassedThisQuota = false;
            IsPinnedToFogSlot = false;
            PassEffectsSuppressed = false;
        }

        public PlayingCardInstance CloneShallow()
        {
            return new PlayingCardInstance(InstanceId, Suit, CornerA, CornerB, IsFlipped, PlagueSuit)
            {
                WasPassedThisQuota = WasPassedThisQuota,
                IsPinnedToFogSlot = IsPinnedToFogSlot,
                PassEffectsSuppressed = PassEffectsSuppressed
            };
        }
    }
}

using System;
using System.Collections.Generic;

namespace PasserCard.Cards
{
    public static class PlayingCardFactory
    {
        public static PlayingCardInstance Create(Suit suit, Rank cornerA, Rank cornerB, PlagueSuit plague = PlagueSuit.None)
        {
            return new PlayingCardInstance(Guid.NewGuid(), suit, cornerA, cornerB, plagueSuit: plague);
        }

        public static List<PlayingCardInstance> CreateStandardDeck(bool dualRank = false, Random? random = null)
        {
            var rng = random ?? new Random();
            var deck = new List<PlayingCardInstance>(52);

            foreach (Suit suit in Enum.GetValues(typeof(Suit)))
            {
                for (var rankValue = (int)Rank.Two; rankValue <= (int)Rank.Ace; rankValue++)
                {
                    var rank = (Rank)rankValue;
                    Rank cornerB;

                    if (!dualRank)
                    {
                        cornerB = rank;
                    }
                    else
                    {
                        var offset = rng.Next(-2, 3);
                        cornerB = RankExtensions.ClampRank(rankValue + offset);
                    }

                    deck.Add(Create(suit, rank, cornerB));
                }
            }

            return deck;
        }
    }
}

