namespace PasserCard.Poker
{
    public static class HandScoreTable
    {
        private static readonly Dictionary<HandCategory, float> CategoryMult = new()
        {
            { HandCategory.HighCard, 1f },
            { HandCategory.Pair, 2f },
            { HandCategory.TwoPair, 2f },
            { HandCategory.ThreeOfAKind, 3f },
            { HandCategory.Straight, 4f },
            { HandCategory.Flush, 4f },
            { HandCategory.FullHouse, 4f },
            { HandCategory.FourOfAKind, 7f },
            { HandCategory.StraightFlush, 8f },
            { HandCategory.RoyalFlush, 8f }
        };

        private static readonly Dictionary<HandCategory, int> CategoryBaseChips = new()
        {
            { HandCategory.HighCard, 5 },
            { HandCategory.Pair, 10 },
            { HandCategory.TwoPair, 20 },
            { HandCategory.ThreeOfAKind, 30 },
            { HandCategory.Straight, 30 },
            { HandCategory.Flush, 35 },
            { HandCategory.FullHouse, 40 },
            { HandCategory.FourOfAKind, 60 },
            { HandCategory.StraightFlush, 100 },
            { HandCategory.RoyalFlush, 100 }
        };

        public static float GetMult(HandCategory category) => CategoryMult[category];

        public static int GetBaseChips(HandCategory category) => CategoryBaseChips[category];
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using PasserCard.Cards;

namespace PasserCard.Poker
{
    public static class PokerHandEvaluator
    {
        public static PokerHandResult Evaluate(IReadOnlyList<ScoringCard> cards, float multModifier = 1f)
        {
            if (cards == null || cards.Count == 0)
            {
                throw new ArgumentException("At least one card is required.", nameof(cards));
            }

            if (cards.Count > 5)
            {
                throw new ArgumentException("At most five cards can be scored.", nameof(cards));
            }

            var category = DetectCategory(cards);
            var rankChips = 0;
            for (var i = 0; i < cards.Count; i++)
            {
                rankChips += cards[i].Rank.ToSortValue();
                rankChips += cards[i].BonusChips;
            }

            var chips = HandScoreTable.GetBaseChips(category) + rankChips;
            var mult = HandScoreTable.GetMult(category) * multModifier;
            var total = (int)Math.Round(chips * mult);
            return new PokerHandResult(category, chips, mult, total);
        }

        public static HandCategory DetectCategory(IReadOnlyList<ScoringCard> cards)
        {
            var flushCards = cards.Where(c => c.CountsForFlush).ToList();
            var straightCards = cards.Where(c => c.CountsForStraight).ToList();

            var isFlush = flushCards.Count == cards.Count && cards.Count >= 5 && flushCards.Select(c => c.Suit).Distinct().Count() == 1;
            var straightRanks = isFlush ? flushCards : straightCards;
            var isStraight = straightRanks.Count >= 5 && IsStraight(straightRanks.Select(c => c.Rank).ToList());

            if (isFlush && isStraight)
            {
                var ranks = flushCards.Select(c => c.Rank).OrderByDescending(r => r.ToSortValue()).ToList();
                if (ranks[0] == Rank.Ace && ranks[1] == Rank.King)
                {
                    return HandCategory.RoyalFlush;
                }

                return HandCategory.StraightFlush;
            }

            var rankGroups = cards
                .GroupBy(c => c.Rank)
                .Select(g => new { Rank = g.Key, Count = g.Count() })
                .OrderByDescending(g => g.Count)
                .ThenByDescending(g => g.Rank.ToSortValue())
                .ToList();

            if (rankGroups.Count > 0 && rankGroups[0].Count == 4)
            {
                return HandCategory.FourOfAKind;
            }

            if (rankGroups.Count >= 2 && rankGroups[0].Count == 3 && rankGroups[1].Count == 2)
            {
                return HandCategory.FullHouse;
            }

            if (isFlush)
            {
                return HandCategory.Flush;
            }

            if (isStraight)
            {
                return HandCategory.Straight;
            }

            if (rankGroups.Count > 0 && rankGroups[0].Count == 3)
            {
                return HandCategory.ThreeOfAKind;
            }

            if (rankGroups.Count >= 2 && rankGroups[0].Count == 2 && rankGroups[1].Count == 2)
            {
                return HandCategory.TwoPair;
            }

            if (rankGroups.Count > 0 && rankGroups[0].Count == 2)
            {
                return HandCategory.Pair;
            }

            return HandCategory.HighCard;
        }

        private static bool IsStraight(List<Rank> ranks)
        {
            if (ranks.Count < 5)
            {
                return false;
            }

            var values = ranks.Select(r => r.ToSortValue()).Distinct().OrderBy(v => v).ToList();
            if (values.Count < 5)
            {
                return false;
            }

            for (var start = 0; start <= values.Count - 5; start++)
            {
                var sequential = true;
                for (var i = 1; i < 5; i++)
                {
                    if (values[start + i] != values[start] + i)
                    {
                        sequential = false;
                        break;
                    }
                }

                if (sequential)
                {
                    return true;
                }
            }

            var wheel = new[] { 2, 3, 4, 5, 14 };
            return wheel.All(w => values.Contains(w));
        }
    }
}

using PasserCard.Cards;
using PasserCard.Run;

namespace PasserCard.Pass
{
    public sealed class PassState
    {
        public int PassesUsed { get; set; }
        public int HeartPassCoinLayers { get; set; }
        public bool MustDoublePassNext { get; set; }
    }

    public readonly struct PassResult
    {
        public PassResult(bool success, string message, bool consumedPassToken)
        {
            Success = success;
            Message = message;
            ConsumedPassToken = consumedPassToken;
        }

        public bool Success { get; }
        public string Message { get; }
        public bool ConsumedPassToken { get; }
    }

    public static class SuitPassRules
    {
        public static PassResult TryPass(PlayingCardInstance card, PassState state, SoulCoinWallet wallet, int passLimit)
        {
            if (card.IsPinnedToFogSlot)
            {
                return new PassResult(false, "Pinned fog cards cannot pass.", false);
            }

            if (MustDoublePass(card, state))
            {
                card.TogglePassFace();
                card.TogglePassFace();
                state.MustDoublePassNext = false;
                card.WasPassedThisQuota = true;
                return new PassResult(true, "Double pass resolved.", false);
            }

            var consumesToken = card.Suit != Suit.Clubs || card.IsPlagued;
            if (consumesToken && state.PassesUsed >= passLimit)
            {
                return new PassResult(false, "Pass limit reached.", false);
            }

            if (!TryPayPassCost(card, wallet, out var payMessage))
            {
                return new PassResult(false, payMessage, false);
            }

            card.TogglePassFace();
            card.WasPassedThisQuota = true;

            if (consumesToken)
            {
                state.PassesUsed++;
            }

            ApplyPostPassEffects(card, state, wallet);
            return new PassResult(true, "Passed.", consumesToken);
        }

        public static ScoringCard ToScoringCard(PlayingCardInstance card, bool inFogSlot)
        {
            var rank = card.EffectiveRank;
            var countsForStraight = true;
            var countsForFlush = true;
            var bonusChips = 0;

            if (!inFogSlot && !card.PassEffectsSuppressed)
            {
                ApplyScoringModifiers(card, ref rank, ref countsForStraight, ref countsForFlush, ref bonusChips);
            }

            return new ScoringCard(rank, card.Suit, countsForStraight, countsForFlush, bonusChips);
        }

        private static bool MustDoublePass(PlayingCardInstance card, PassState state)
        {
            return state.MustDoublePassNext && card.Suit == Suit.Clubs && !card.IsPlagued;
        }

        private static bool TryPayPassCost(PlayingCardInstance card, SoulCoinWallet wallet, out string message)
        {
            if (card.IsPlagued && card.PlagueSuit == PlagueSuit.RustRot)
            {
                if (!wallet.TrySpend(1))
                {
                    message = "Not enough soul coins for rust rot pass.";
                    return false;
                }
            }
            else if (card.Suit == Suit.Diamonds)
            {
                if (!wallet.TrySpend(1))
                {
                    message = "Not enough soul coins for diamond pass.";
                    return false;
                }
            }

            message = string.Empty;
            return true;
        }

        private static void ApplyPostPassEffects(PlayingCardInstance card, PassState state, SoulCoinWallet wallet)
        {
            if (card.IsPlagued)
            {
                ApplyPlaguePostPass(card, state, wallet);
                return;
            }

            switch (card.Suit)
            {
                case Suit.Hearts:
                    wallet.Add(1);
                    state.HeartPassCoinLayers = System.Math.Min(3, state.HeartPassCoinLayers + 1);
                    break;
                case Suit.Clubs:
                    state.MustDoublePassNext = true;
                    break;
            }
        }

        private static void ApplyPlaguePostPass(PlayingCardInstance card, PassState state, SoulCoinWallet wallet)
        {
            switch (card.PlagueSuit)
            {
                case PlagueSuit.FesterBlood:
                    wallet.Add(1);
                    wallet.TrySpend(1);
                    break;
                case PlagueSuit.WitherBlight:
                    state.MustDoublePassNext = true;
                    break;
            }
        }

        private static void ApplyScoringModifiers(
            PlayingCardInstance card,
            ref Rank rank,
            ref bool countsForStraight,
            ref bool countsForFlush,
            ref int bonusChips)
        {
            if (card.IsPlagued)
            {
                ApplyPlagueScoring(card, ref rank, ref countsForStraight, ref countsForFlush, ref bonusChips);
                return;
            }

            switch (card.Suit)
            {
                case Suit.Spades:
                    rank = RankExtensions.ClampRank(rank.ToSortValue() + 1);
                    countsForStraight = false;
                    break;
                case Suit.Diamonds:
                    bonusChips += card.IsPlagued ? 7 : 15;
                    break;
            }
        }

        private static void ApplyPlagueScoring(
            PlayingCardInstance card,
            ref Rank rank,
            ref bool countsForStraight,
            ref bool countsForFlush,
            ref int bonusChips)
        {
            switch (card.PlagueSuit)
            {
                case PlagueSuit.CorruptSpring:
                    rank = RankExtensions.ClampRank(rank.ToSortValue() + 1);
                    countsForStraight = false;
                    countsForFlush = false;
                    break;
                case PlagueSuit.RustRot:
                    bonusChips += 7;
                    break;
            }
        }

        public static float GetHeartChipsPenalty(PassState state)
        {
            return 1f - 0.1f * state.HeartPassCoinLayers;
        }
    }
}

namespace PasserCard.Run
{
    public sealed class SoulCoinWallet
    {
        public SoulCoinWallet(int startingCoins = 0)
        {
            Balance = startingCoins;
        }

        public int Balance { get; private set; }

        public void Add(int amount)
        {
            if (amount <= 0)
            {
                return;
            }

            Balance += amount;
        }

        public bool TrySpend(int amount)
        {
            if (amount <= 0)
            {
                return true;
            }

            if (Balance < amount)
            {
                return false;
            }

            Balance -= amount;
            return true;
        }
    }
}

