using PasserCard.Cards;

namespace PasserCard.Table
{
    public enum PlaySlotKind
    {
        Clear = 0,
        Fog = 1
    }

    public sealed class PlaySlot
    {
        public PlaySlot(int index)
        {
            Index = index;
        }

        public int Index { get; }
        public PlaySlotKind Kind { get; private set; } = PlaySlotKind.Clear;
        public PlayingCardInstance? Card { get; private set; }

        public bool IsEmpty => Card == null;
        public bool IsFog => Kind == PlaySlotKind.Fog;

        public void SetFog(bool fog) => Kind = fog ? PlaySlotKind.Fog : PlaySlotKind.Clear;

        public bool TryPinCard(PlayingCardInstance card)
        {
            if (Card != null || !IsFog)
            {
                return false;
            }

            Card = card;
            card.IsPinnedToFogSlot = true;
            card.PassEffectsSuppressed = true;
            return true;
        }

        public bool TryPlaceCard(PlayingCardInstance card)
        {
            if (Card != null)
            {
                return false;
            }

            if (IsFog && card.WasPassedThisQuota)
            {
                return false;
            }

            Card = card;
            if (IsFog)
            {
                card.PassEffectsSuppressed = true;
            }

            return true;
        }

        public PlayingCardInstance? ClearCard()
        {
            var existing = Card;
            if (existing == null)
            {
                return null;
            }

            Card = null;
            return existing;
        }

        public void ResetQuota()
        {
            Card = null;
        }
    }
}

using System;
using System.Collections.Generic;
using PasserCard.Cards;

namespace PasserCard.Table
{
    public sealed class PlayArea
    {
        public const int SlotCount = 5;

        private readonly PlaySlot[] _slots =
        {
            new(0),
            new(1),
            new(2),
            new(3),
            new(4)
        };

        public IReadOnlyList<PlaySlot> Slots => _slots;

        public void RefreshFog(int fogCount, Random random)
        {
            for (var i = 0; i < _slots.Length; i++)
            {
                _slots[i].SetFog(false);
                _slots[i].ResetQuota();
            }

            fogCount = Math.Clamp(fogCount, 0, SlotCount);
            var indices = new List<int> { 0, 1, 2, 3, 4 };
            for (var i = 0; i < fogCount; i++)
            {
                var pick = random.Next(indices.Count);
                var slotIndex = indices[pick];
                indices.RemoveAt(pick);
                _slots[slotIndex].SetFog(true);
            }
        }

        public bool TryPinToFogSlot(int slotIndex, PlayingCardInstance card)
        {
            if (slotIndex < 0 || slotIndex >= SlotCount)
            {
                return false;
            }

            return _slots[slotIndex].TryPinCard(card);
        }

        public bool TryPlaceCard(int slotIndex, PlayingCardInstance card)
        {
            if (slotIndex < 0 || slotIndex >= SlotCount)
            {
                return false;
            }

            return _slots[slotIndex].TryPlaceCard(card);
        }

        public List<PlayingCardInstance> GetCommittedCards()
        {
            var cards = new List<PlayingCardInstance>();
            for (var i = 0; i < _slots.Length; i++)
            {
                if (_slots[i].Card != null)
                {
                    cards.Add(_slots[i].Card!);
                }
            }

            return cards;
        }

        public void ResetSlots()
        {
            for (var i = 0; i < _slots.Length; i++)
            {
                _slots[i].ResetQuota();
            }
        }
    }
}

namespace PasserCard.Encounter
{
    public enum EncounterPhase
    {
        QuotaSetup = 0,
        Discard = 1,
        PrePinFog = 2,
        Pass = 3,
        PlayToSlots = 4,
        ResolveQuota = 5,
        EncounterComplete = 6
    }

    public sealed class EncounterConfig
    {
        public int HandSize { get; set; } = 8;
        public int PlayQuotas { get; set; } = 4;
        public int DiscardsRemaining { get; set; } = 3;
        public int PassLimit { get; set; } = 5;
        public int MistFogSlots { get; set; } = 2;
        public int TargetScore { get; set; } = 120;
        public int RetaliationCoinLoss { get; set; } = 2;
        public int VictoryCoinReward { get; set; } = 8;
        public int DefeatCoinLoss { get; set; } = 5;
    }
}

using System;
using System.Collections.Generic;
using PasserCard.Cards;
using PasserCard.Gameplay;
using PasserCard.Pass;
using PasserCard.Poker;
using PasserCard.Run;
using PasserCard.Table;

namespace PasserCard.Encounter
{
    public sealed class EncounterSession
    {
        private readonly EncounterConfig _config;
        private readonly Deck _drawPile;
        private readonly Hand _hand;
        private readonly PlayArea _playArea;
        private readonly PassState _passState = new();
        private readonly Random _random;

        public EncounterSession(
            EncounterConfig config,
            IEnumerable<PlayingCardInstance> runDeck,
            SoulCoinWallet wallet,
            Random? random = null)
        {
            _config = config ?? throw new ArgumentNullException(nameof(config));
            Wallet = wallet ?? throw new ArgumentNullException(nameof(wallet));
            _random = random ?? new Random();

            _drawPile = new Deck();
            _drawPile.AddRange(runDeck);
            _drawPile.Shuffle();

            _hand = new Hand(config.HandSize);
            _playArea = new PlayArea();

            Phase = EncounterPhase.QuotaSetup;
            CurrentQuota = 0;
            DiscardsRemaining = config.DiscardsRemaining;
            BestScore = 0;
            LastQuotaScore = 0;
        }

        public EncounterPhase Phase { get; private set; }
        public int CurrentQuota { get; private set; }
        public int DiscardsRemaining { get; private set; }
        public int BestScore { get; private set; }
        public int LastQuotaScore { get; private set; }
        public bool IsVictory => BestScore >= _config.TargetScore;
        public bool IsComplete => Phase == EncounterPhase.EncounterComplete;

        public SoulCoinWallet Wallet { get; }
        public Hand Hand => _hand;
        public PlayArea PlayArea => _playArea;
        public PassState PassState => _passState;
        public EncounterConfig Config => _config;

        public void StartEncounter()
        {
            FillHand();
            BeginQuota();
        }

        public void BeginQuota()
        {
            if (CurrentQuota >= _config.PlayQuotas)
            {
                CompleteEncounter();
                return;
            }

            CurrentQuota++;
            Phase = EncounterPhase.QuotaSetup;
            _passState.PassesUsed = 0;
            _passState.MustDoublePassNext = false;

            for (var i = 0; i < _hand.Count; i++)
            {
                _hand.Cards[i].ResetQuotaFlags();
            }

            _playArea.RefreshFog(_config.MistFogSlots, _random);
            Phase = EncounterPhase.Discard;
        }

        public bool TryDiscard(Guid instanceId)
        {
            if (Phase != EncounterPhase.Discard && Phase != EncounterPhase.PrePinFog && Phase != EncounterPhase.Pass)
            {
                return false;
            }

            if (DiscardsRemaining <= 0)
            {
                return false;
            }

            if (!_hand.TryRemove(instanceId, out var card))
            {
                return false;
            }

            _drawPile.Add(card);
            _drawPile.Shuffle();
            if (!_drawPile.TryDraw(out var replacement))
            {
                return false;
            }

            _hand.TryAdd(replacement);
            DiscardsRemaining--;
            return true;
        }

        public void EnterPrePinPhase() => Phase = EncounterPhase.PrePinFog;

        public void EnterPassPhase() => Phase = EncounterPhase.Pass;

        public bool TryPinToFogSlot(int slotIndex, Guid cardInstanceId)
        {
            if (Phase != EncounterPhase.PrePinFog && Phase != EncounterPhase.Discard)
            {
                return false;
            }

            if (!_hand.TryRemove(cardInstanceId, out var card))
            {
                return false;
            }

            if (!_playArea.TryPinToFogSlot(slotIndex, card))
            {
                _hand.TryAdd(card);
                return false;
            }

            return true;
        }

        public PassResult TryPassCard(Guid instanceId)
        {
            if (Phase != EncounterPhase.Pass)
            {
                return new PassResult(false, "Not in pass phase.", false);
            }

            for (var i = 0; i < _hand.Count; i++)
            {
                var card = _hand.Cards[i];
                if (card.InstanceId != instanceId)
                {
                    continue;
                }

                return SuitPassRules.TryPass(card, _passState, Wallet, _config.PassLimit);
            }

            return new PassResult(false, "Card not in hand.", false);
        }

        public void EnterPlayPhase() => Phase = EncounterPhase.PlayToSlots;

        public bool TryPlaceCard(int slotIndex, Guid cardInstanceId)
        {
            if (Phase != EncounterPhase.PlayToSlots)
            {
                return false;
            }

            if (!_hand.TryRemove(cardInstanceId, out var card))
            {
                return false;
            }

            if (!_playArea.TryPlaceCard(slotIndex, card))
            {
                _hand.TryAdd(card);
                return false;
            }

            return true;
        }

        public PokerHandResult ResolveCurrentQuota(float extraMult = 1f)
        {
            if (Phase != EncounterPhase.PlayToSlots)
            {
                throw new InvalidOperationException("Cannot resolve outside play phase.");
            }

            var committed = _playArea.GetCommittedCards();
            if (committed.Count == 0)
            {
                throw new InvalidOperationException("At least one card must be committed.");
            }

            var scoringCards = new List<ScoringCard>(committed.Count);
            var hasDeath = false;
            for (var i = 0; i < committed.Count; i++)
            {
                var card = committed[i];
                var slot = _playArea.Slots[i];
                for (var s = 0; s < _playArea.Slots.Count; s++)
                {
                    if (_playArea.Slots[s].Card == card)
                    {
                        slot = _playArea.Slots[s];
                        break;
                    }
                }

                scoringCards.Add(SuitPassRules.ToScoringCard(card, slot.IsFog));
            }

            var mult = extraMult * SuitPassRules.GetHeartChipsPenalty(_passState);
            var result = PokerHandEvaluator.Evaluate(scoringCards, mult);
            LastQuotaScore = result.TotalScore;
            if (result.TotalScore > BestScore)
            {
                BestScore = result.TotalScore;
            }

            Phase = EncounterPhase.ResolveQuota;
            return result;
        }

        public void FinishQuota()
        {
            if (Phase != EncounterPhase.ResolveQuota)
            {
                return;
            }

            if (!IsVictory && CurrentQuota < _config.PlayQuotas)
            {
                Wallet.TrySpend(_config.RetaliationCoinLoss);
            }

            ReturnCommittedCardsToDeck();
            FillHand();
            BeginQuota();
        }

        public void CompleteEncounter()
        {
            Phase = EncounterPhase.EncounterComplete;
            if (IsVictory)
            {
                Wallet.Add(_config.VictoryCoinReward);
            }
            else
            {
                Wallet.TrySpend(_config.DefeatCoinLoss);
            }
        }

        private void FillHand()
        {
            while (_hand.Count < _config.HandSize && _drawPile.TryDraw(out var card))
            {
                _hand.TryAdd(card);
            }
        }

        private void ReturnCommittedCardsToDeck()
        {
            for (var i = 0; i < _playArea.Slots.Count; i++)
            {
                var card = _playArea.Slots[i].ClearCard();
                if (card != null)
                {
                    card.ResetQuotaFlags();
                    _drawPile.Add(card);
                }
            }

            _drawPile.Shuffle();
        }
    }
}

