using System;
using PasserCard.Cards;
using PasserCard.Encounter;
using PasserCard.Run;
using UnityEngine;

namespace PasserCard.Core
{
    /// <summary>
    /// Scene entry point for the Phase 1 encounter prototype.
    /// </summary>
    public sealed class GameBootstrap : MonoBehaviour
    {
        [SerializeField] private int startingSoulCoins = 20;
        [SerializeField] private int guardianTargetScore = 120;
        [SerializeField] private bool runDemoOnStart = true;

        private EncounterSession? _session;

        public EncounterSession? Session => _session;

        private void Start()
        {
            if (!runDemoOnStart)
            {
                return;
            }

            RunDemoEncounter();
        }

        [ContextMenu("Run Demo Encounter")]
        public void RunDemoEncounter()
        {
            var config = new EncounterConfig
            {
                TargetScore = guardianTargetScore,
                MistFogSlots = 2
            };

            var wallet = new SoulCoinWallet(startingSoulCoins);
            var deck = PlayingCardFactory.CreateStandardDeck(dualRank: true, random: new Random(42));
            _session = new EncounterSession(config, deck, wallet, new Random(42));
            _session.StartEncounter();

            Debug.Log($"[PasserCard] Encounter started. Target={config.TargetScore}, SoulCoins={wallet.Balance}, Hand={_session.Hand.Count}");
            LogPlayArea();
        }

        [ContextMenu("Demo Pass First Hand Card")]
        public void DemoPassFirstHandCard()
        {
            if (_session == null || _session.Hand.Count == 0)
            {
                return;
            }

            _session.EnterPassPhase();
            var card = _session.Hand.Cards[0];
            var result = _session.TryPassCard(card.InstanceId);
            Debug.Log($"[PasserCard] Pass {card.Suit} {card.EffectiveRank}: {result.Message}");
        }

        [ContextMenu("Demo Play And Score")]
        public void DemoPlayAndScore()
        {
            if (_session == null)
            {
                return;
            }

            _session.EnterPlayPhase();
            var cardsToPlay = Math.Min(5, _session.Hand.Count);
            for (var i = 0; i < cardsToPlay; i++)
            {
                _session.TryPlaceCard(i, _session.Hand.Cards[0].InstanceId);
            }

            var score = _session.ResolveCurrentQuota();
            Debug.Log($"[PasserCard] Quota {_session.CurrentQuota}: {score.Category} => {score.TotalScore} (best {_session.BestScore})");
            _session.FinishQuota();
            LogPlayArea();
        }

        private void LogPlayArea()
        {
            if (_session == null)
            {
                return;
            }

            for (var i = 0; i < _session.PlayArea.Slots.Count; i++)
            {
                var slot = _session.PlayArea.Slots[i];
                var fog = slot.IsFog ? "FOG" : "CLR";
                Debug.Log($"[PasserCard] Slot {i + 1}: {fog}");
            }
        }
    }
}

using System.Collections.Generic;
using NUnit.Framework;
using PasserCard.Cards;
using PasserCard.Poker;

namespace PasserCard.Tests
{
    public sealed class PokerHandEvaluatorTests
    {
        [Test]
        public void Evaluate_Pair_ReturnsPairCategory()
        {
            var cards = new List<ScoringCard>
            {
                new(Rank.King, Suit.Spades, true, true),
                new(Rank.King, Suit.Hearts, true, true),
                new(Rank.Five, Suit.Clubs, true, true)
            };

            var result = PokerHandEvaluator.Evaluate(cards);

            Assert.AreEqual(HandCategory.Pair, result.Category);
            Assert.Greater(result.TotalScore, 0);
        }

        [Test]
        public void Evaluate_SpadesPassModifier_ExcludesStraight()
        {
            var cards = new List<ScoringCard>
            {
                new(Rank.Ten, Suit.Spades, false, true),
                new(Rank.Jack, Suit.Spades, true, true),
                new(Rank.Queen, Suit.Spades, true, true),
                new(Rank.King, Suit.Spades, true, true),
                new(Rank.Ace, Suit.Spades, true, true)
            };

            var category = PokerHandEvaluator.DetectCategory(cards);

            Assert.AreEqual(HandCategory.Flush, category);
        }

        [Test]
        public void Evaluate_Straight_DetectsWheel()
        {
            var cards = new List<ScoringCard>
            {
                new(Rank.Ace, Suit.Hearts, true, true),
                new(Rank.Two, Suit.Hearts, true, true),
                new(Rank.Three, Suit.Hearts, true, true),
                new(Rank.Four, Suit.Hearts, true, true),
                new(Rank.Five, Suit.Hearts, true, true)
            };

            var category = PokerHandEvaluator.DetectCategory(cards);

            Assert.AreEqual(HandCategory.Straight, category);
        }
    }
