using PasserCard.Cards;

namespace PasserCard.UI
{
    public static class CardDisplayFormatter
    {
        public static string FormatCard(PlayingCardInstance card)
        {
            var suit = SuitSymbol(card.Suit);
            var active = RankLabel(card.EffectiveRank);
            var cornerA = RankLabel(card.CornerA);
            var cornerB = RankLabel(card.CornerB);
            var face = card.IsFlipped ? "B" : "A";
            return $"{suit} {active} ({cornerA}/{cornerB}) {face}";
        }

        public static string FormatCardShort(PlayingCardInstance card)
        {
            return $"{SuitSymbol(card.Suit)}{RankLabel(card.EffectiveRank)}";
        }

        public static string SuitSymbol(Suit suit) =>
            suit switch
            {
                Suit.Spades => "♠",
                Suit.Hearts => "♥",
                Suit.Clubs => "♣",
                Suit.Diamonds => "♦",
                _ => "?"
            };

        public static string RankLabel(Rank rank) =>
            rank switch
            {
                Rank.Ace => "A",
                Rank.King => "K",
                Rank.Queen => "Q",
                Rank.Jack => "J",
                Rank.Ten => "10",
                _ => ((int)rank).ToString()
            };
    }
}

using System;
using UnityEngine;
using UnityEngine.UI;

namespace PasserCard.UI
{
    public static class EncounterUIBuilder
    {
        public sealed class BuiltUI
        {
            public Text StatusText = null!;
            public Text MessageText = null!;
            public Transform HandContainer = null!;
            public Button[] SlotButtons = null!;
            public Text[] SlotLabels = null!;
            public Button DiscardButton = null!;
            public Button PassButton = null!;
            public Button PrePinButton = null!;
            public Button ToPassPhaseButton = null!;
            public Button ToPlayPhaseButton = null!;
            public Button SubmitButton = null!;
            public Button NextQuotaButton = null!;
        }

        private static readonly Color PanelColor = new(0.1f, 0.12f, 0.18f, 0.95f);
        private static readonly Color FogSlotColor = new(0.25f, 0.28f, 0.35f, 1f);
        private static readonly Color ClearSlotColor = new(0.18f, 0.22f, 0.3f, 1f);
        private static readonly Color CardColor = new(0.92f, 0.92f, 0.96f, 1f);
        private static readonly Color CardSelectedColor = new(1f, 0.85f, 0.45f, 1f);
        private static readonly Color RedSuitColor = new(0.85f, 0.2f, 0.25f, 1f);
        private static readonly Color BlackSuitColor = new(0.12f, 0.12f, 0.15f, 1f);

        public static BuiltUI Create(Transform parent)
        {
            var canvasGo = new GameObject("EncounterCanvas", typeof(Canvas), typeof(CanvasScaler), typeof(GraphicRaycaster));
            canvasGo.transform.SetParent(parent, false);

            var canvas = canvasGo.GetComponent<Canvas>();
            canvas.renderMode = RenderMode.ScreenSpaceOverlay;

            var scaler = canvasGo.GetComponent<CanvasScaler>();
            scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
            scaler.referenceResolution = new Vector2(1920, 1080);

            if (UnityEngine.Object.FindObjectOfType<UnityEngine.EventSystems.EventSystem>() == null)
            {
                var eventSystem = new GameObject("EventSystem",
                    typeof(UnityEngine.EventSystems.EventSystem),
                    typeof(UnityEngine.EventSystems.StandaloneInputModule));
            }

            var root = CreatePanel(canvasGo.transform, "Root", PanelColor, Vector2.zero, Vector2.one, Vector2.zero, Vector2.zero);

            var status = CreateText(root.transform, "StatusText", 22, TextAnchor.UpperLeft,
                new Vector2(0, 1), new Vector2(1, 1), new Vector2(24, -24), new Vector2(-24, -100));
            var message = CreateText(root.transform, "MessageText", 18, TextAnchor.UpperLeft,
                new Vector2(0, 1), new Vector2(1, 1), new Vector2(24, -108), new Vector2(-24, -160));

            var slotRow = CreatePanel(root.transform, "PlaySlots", new Color(0, 0, 0, 0),
                new Vector2(0.5f, 0.55f), new Vector2(0.5f, 0.55f), new Vector2(-420, -70), new Vector2(420, 70));

            var slotButtons = new Button[5];
            var slotLabels = new Text[5];
            for (var i = 0; i < 5; i++)
            {
                var xMin = i * 168;
                var slot = CreateButton(slotRow.transform, $"Slot{i + 1}", ClearSlotColor,
                    new Vector2(xMin, 0), new Vector2(xMin + 160, 140), $"槽 {i + 1}");
                slotButtons[i] = slot;
                slotLabels[i] = slot.GetComponentInChildren<Text>();
            }

            var handRow = CreatePanel(root.transform, "HandRow", new Color(0, 0, 0, 0),
                new Vector2(0.5f, 0.18f), new Vector2(0.5f, 0.18f), new Vector2(-700, -80), new Vector2(700, 80));

            var actionRow = CreatePanel(root.transform, "Actions", new Color(0, 0, 0, 0),
                new Vector2(0.5f, 0.04f), new Vector2(0.5f, 0.04f), new Vector2(-700, 0), new Vector2(700, 56));

            return new BuiltUI
            {
                StatusText = status,
                MessageText = message,
                HandContainer = handRow.transform,
                SlotButtons = slotButtons,
                SlotLabels = slotLabels,
                DiscardButton = CreateActionButton(actionRow.transform, "Discard", 0, "弃牌"),
                PrePinButton = CreateActionButton(actionRow.transform, "PrePin", 1, "预钉雾槽"),
                ToPassPhaseButton = CreateActionButton(actionRow.transform, "ToPass", 2, "→ Pass"),
                PassButton = CreateActionButton(actionRow.transform, "Pass", 3, "Pass 选中"),
                ToPlayPhaseButton = CreateActionButton(actionRow.transform, "ToPlay", 4, "→ 出牌"),
                SubmitButton = CreateActionButton(actionRow.transform, "Submit", 5, "计分"),
                NextQuotaButton = CreateActionButton(actionRow.transform, "Next", 6, "下一配额")
            };
        }

        public static Button CreateHandCardButton(Transform parent, string label, bool selected, Action onClick)
        {
            var button = CreateButton(parent, "Card", selected ? CardSelectedColor : CardColor,
                Vector2.zero, Vector2.zero, label, 110, 150);
            var layout = button.gameObject.AddComponent<LayoutElement>();
            layout.preferredWidth = 110;
            layout.preferredHeight = 150;

            var text = button.GetComponentInChildren<Text>();
            text.color = label.Contains("♥") || label.Contains("♦") ? RedSuitColor : BlackSuitColor;
            text.fontSize = 16;
            button.onClick.AddListener(() => onClick());
            return button;
        }

        public static void StyleSlot(Button slot, bool fog, bool hasCard)
        {
            var image = slot.GetComponent<Image>();
            image.color = fog ? FogSlotColor : ClearSlotColor;
            if (hasCard)
            {
                image.color = fog ? new Color(0.35f, 0.38f, 0.48f, 1f) : new Color(0.28f, 0.34f, 0.45f, 1f);
            }
        }

        private static Button CreateActionButton(Transform parent, string name, int index, string label)
        {
            var width = 190f;
            var x = index * (width + 8f);
            return CreateButton(parent, name, new Color(0.24f, 0.3f, 0.42f, 1f),
                new Vector2(x, 0), new Vector2(x + width, 56), label, width, 56);
        }

        private static GameObject CreatePanel(Transform parent, string name, Color color,
            Vector2 anchorMin, Vector2 anchorMax, Vector2 offsetMin, Vector2 offsetMax)
        {
            var go = new GameObject(name, typeof(RectTransform), typeof(Image));
            go.transform.SetParent(parent, false);
            var image = go.GetComponent<Image>();
            image.color = color;
            var rect = go.GetComponent<RectTransform>();
            rect.anchorMin = anchorMin;
            rect.anchorMax = anchorMax;
            rect.offsetMin = offsetMin;
            rect.offsetMax = offsetMax;
            return go;
        }

        private static Text CreateText(Transform parent, string name, int fontSize, TextAnchor anchor,
            Vector2 anchorMin, Vector2 anchorMax, Vector2 offsetMin, Vector2 offsetMax)
        {
            var go = new GameObject(name, typeof(RectTransform), typeof(Text));
            go.transform.SetParent(parent, false);
            var text = go.GetComponent<Text>();
            text.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
            text.fontSize = fontSize;
            text.color = Color.white;
            text.alignment = anchor;
            text.horizontalOverflow = HorizontalWrapMode.Wrap;
            text.verticalOverflow = VerticalWrapMode.Overflow;
            var rect = go.GetComponent<RectTransform>();
            rect.anchorMin = anchorMin;
            rect.anchorMax = anchorMax;
            rect.offsetMin = offsetMin;
            rect.offsetMax = offsetMax;
            return text;
        }

        private static Button CreateButton(Transform parent, string name, Color color,
            Vector2 offsetMin, Vector2 offsetMax, string label, float width = 160, float height = 140)
        {
            var go = new GameObject(name, typeof(RectTransform), typeof(Image), typeof(Button));
            go.transform.SetParent(parent, false);
            var rect = go.GetComponent<RectTransform>();
            rect.anchorMin = new Vector2(0, 0);
            rect.anchorMax = new Vector2(0, 0);
            rect.pivot = new Vector2(0, 0);
            rect.sizeDelta = new Vector2(width, height);
            rect.anchoredPosition = offsetMin;

            if (offsetMax.x > offsetMin.x)
            {
                rect.sizeDelta = new Vector2(offsetMax.x - offsetMin.x, offsetMax.y - offsetMin.y);
            }

            var image = go.GetComponent<Image>();
            image.color = color;

            var textGo = new GameObject("Label", typeof(RectTransform), typeof(Text));
            textGo.transform.SetParent(go.transform, false);
            var textRect = textGo.GetComponent<RectTransform>();
            textRect.anchorMin = Vector2.zero;
            textRect.anchorMax = Vector2.one;
            textRect.offsetMin = new Vector2(8, 8);
            textRect.offsetMax = new Vector2(-8, -8);
            var text = textGo.GetComponent<Text>();
            text.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
            text.fontSize = 18;
            text.alignment = TextAnchor.MiddleCenter;
            text.color = Color.white;
            text.text = label;

            var button = go.GetComponent<Button>();
            var colors = button.colors;
            colors.highlightedColor = new Color(0.7f, 0.8f, 1f, 1f);
            colors.pressedColor = new Color(0.5f, 0.6f, 0.85f, 1f);
            button.colors = colors;
            return button;
        }
    }
}

using System;
using System.Collections.Generic;
using PasserCard.Cards;
using PasserCard.Encounter;
using UnityEngine;
using UnityEngine.UI;

namespace PasserCard.UI
{
    public sealed class EncounterUIController : MonoBehaviour
    {
        private EncounterSession? _session;
        private EncounterUIBuilder.BuiltUI? _ui;
        private Guid? _selectedCardId;
        private readonly List<GameObject> _handCardObjects = new();
        private string _lastMessage = string.Empty;

        public void Bind(EncounterSession session)
        {
            _session = session ?? throw new ArgumentNullException(nameof(session));
            EnsureUI();
            WireButtons();
            Refresh();
        }

        private void EnsureUI()
        {
            if (_ui != null)
            {
                return;
            }

            _ui = EncounterUIBuilder.Create(transform);
            var layout = _ui.HandContainer.gameObject.AddComponent<HorizontalLayoutGroup>();
            layout.spacing = 8;
            layout.childAlignment = TextAnchor.MiddleCenter;
            layout.childControlWidth = false;
            layout.childControlHeight = false;
            layout.childForceExpandWidth = false;
            layout.childForceExpandHeight = false;
        }

        private void WireButtons()
        {
            if (_ui == null)
            {
                return;
            }

            _ui.DiscardButton.onClick.AddListener(OnDiscardClicked);
            _ui.PrePinButton.onClick.AddListener(OnPrePinPhaseClicked);
            _ui.ToPassPhaseButton.onClick.AddListener(OnToPassPhaseClicked);
            _ui.PassButton.onClick.AddListener(OnPassClicked);
            _ui.ToPlayPhaseButton.onClick.AddListener(OnToPlayPhaseClicked);
            _ui.SubmitButton.onClick.AddListener(OnSubmitClicked);
            _ui.NextQuotaButton.onClick.AddListener(OnNextQuotaClicked);

            for (var i = 0; i < _ui.SlotButtons.Length; i++)
            {
                var slotIndex = i;
                _ui.SlotButtons[i].onClick.AddListener(() => OnSlotClicked(slotIndex));
            }
        }

        private void OnDiscardClicked()
        {
            if (_session == null || !_selectedCardId.HasValue)
            {
                SetMessage("请先选择一张手牌。");
                return;
            }

            if (_session.TryDiscard(_selectedCardId.Value))
            {
                _selectedCardId = null;
                SetMessage("已弃牌并补牌。");
            }
            else
            {
                SetMessage("无法弃牌（次数用尽或阶段不对）。");
            }

            Refresh();
        }

        private void OnPrePinPhaseClicked()
        {
            _session?.EnterPrePinPhase();
            SetMessage("预钉阶段：选牌后点击迷雾槽。");
            Refresh();
        }

        private void OnToPassPhaseClicked()
        {
            _session?.EnterPassPhase();
            SetMessage("Pass 阶段：选牌后点 Pass。");
            Refresh();
        }

        private void OnPassClicked()
        {
            if (_session == null || !_selectedCardId.HasValue)
            {
                SetMessage("请先选择一张手牌。");
                return;
            }

            var result = _session.TryPassCard(_selectedCardId.Value);
            SetMessage(result.Message);
            Refresh();
        }

        private void OnToPlayPhaseClicked()
        {
            _session?.EnterPlayPhase();
            SetMessage("出牌阶段：选牌后点击空槽。");
            Refresh();
        }

        private void OnSubmitClicked()
        {
            if (_session == null)
            {
                return;
            }

            if (_session.TryResolveCurrentQuota(out var result, out var error))
            {
                SetMessage($"牌型 {result.Category} · 得分 {result.TotalScore} · 最高 {_session.BestScore}");
            }
            else
            {
                SetMessage(error);
            }

            Refresh();
        }

        private void OnNextQuotaClicked()
        {
            if (_session == null)
            {
                return;
            }

            if (_session.Phase == EncounterPhase.ResolveQuota)
            {
                _session.FinishQuota();
                _selectedCardId = null;
                if (_session.IsComplete)
                {
                    var outcome = _session.IsVictory ? "胜利" : "失败";
                    SetMessage($"Encounter 结束：{outcome}。魂币 {_session.Wallet.Balance}");
                }
                else
                {
                    SetMessage("进入下一出牌配额。");
                }
            }
            else
            {
                SetMessage("请先完成计分。");
            }

            Refresh();
        }

        private void OnSlotClicked(int slotIndex)
        {
            if (_session == null)
            {
                return;
            }

            var slot = _session.PlayArea.Slots[slotIndex];
            if (!slot.IsEmpty)
            {
                SetMessage("该槽已有牌。");
                return;
            }

            if (!_selectedCardId.HasValue)
            {
                SetMessage("请先选择手牌。");
                return;
            }

            var cardId = _selectedCardId.Value;
            var success = _session.Phase switch
            {
                EncounterPhase.Discard or EncounterPhase.PrePinFog => _session.TryPinToFogSlot(slotIndex, cardId),
                EncounterPhase.PlayToSlots => _session.TryPlaceCard(slotIndex, cardId),
                _ => false
            };

            if (success)
            {
                _selectedCardId = null;
                SetMessage(_session.Phase == EncounterPhase.PlayToSlots ? "已放入出牌槽。" : "已预钉到迷雾槽。");
            }
            else
            {
                SetMessage("无法放入该槽（阶段不对、非雾槽或该牌已 Pass 过）。");
            }

            Refresh();
        }

        private void OnHandCardClicked(Guid cardId)
        {
            _selectedCardId = _selectedCardId == cardId ? null : cardId;
            Refresh();
        }

        private void Refresh()
        {
            if (_session == null || _ui == null)
            {
                return;
            }

            RefreshStatus();
            RefreshSlots();
            RefreshHand();
            RefreshButtons();
            _ui.MessageText.text = _lastMessage;
        }

        private void RefreshStatus()
        {
            if (_ui == null || _session == null)
            {
                return;
            }

            var fogCount = 0;
            for (var i = 0; i < _session.PlayArea.Slots.Count; i++)
            {
                if (_session.PlayArea.Slots[i].IsFog)
                {
                    fogCount++;
                }
            }

            _ui.StatusText.text =
                $"PasserCard Encounter\n" +
                $"阶段：{_session.PhaseLabel} · 配额 {_session.CurrentQuota}/{_session.Config.PlayQuotas}\n" +
                $"魂币 {_session.Wallet.Balance} · 目标分 {_session.TargetScore} · 最高分 {_session.BestScore}\n" +
                $"Pass {_session.PassesUsed}/{_session.PassLimit} · 弃牌剩余 {_session.DiscardsRemaining} · 迷雾槽 {fogCount}/5";
        }

        private void RefreshSlots()
        {
            if (_ui == null || _session == null)
            {
                return;
            }

            for (var i = 0; i < _ui.SlotButtons.Length; i++)
            {
                var slot = _session.PlayArea.Slots[i];
                var label = slot.IsFog ? $"雾槽{i + 1}" : $"槽{i + 1}";
                if (slot.Card != null)
                {
                    label = $"{label}\n{CardDisplayFormatter.FormatCardShort(slot.Card)}";
                }

                _ui.SlotLabels[i].text = label;
                EncounterUIBuilder.StyleSlot(_ui.SlotButtons[i], slot.IsFog, !slot.IsEmpty);
            }
        }

        private void RefreshHand()
        {
            if (_ui == null || _session == null)
            {
                return;
            }

            for (var i = 0; i < _handCardObjects.Count; i++)
            {
                Destroy(_handCardObjects[i]);
            }

            _handCardObjects.Clear();

            for (var i = 0; i < _session.Hand.Count; i++)
            {
                var card = _session.Hand.Cards[i];
                var selected = _selectedCardId == card.InstanceId;
                var label = CardDisplayFormatter.FormatCard(card);
                var capturedId = card.InstanceId;
                var button = EncounterUIBuilder.CreateHandCardButton(_ui.HandContainer, label, selected,
                    () => OnHandCardClicked(capturedId));
                _handCardObjects.Add(button.gameObject);
            }
        }

        private void RefreshButtons()
        {
            if (_ui == null || _session == null)
            {
                return;
            }

            var phase = _session.Phase;
            var complete = _session.IsComplete;

            _ui.DiscardButton.interactable = !complete && phase is EncounterPhase.Discard or EncounterPhase.PrePinFog or EncounterPhase.Pass;
            _ui.PrePinButton.interactable = !complete && phase == EncounterPhase.Discard;
            _ui.ToPassPhaseButton.interactable = !complete && phase is EncounterPhase.Discard or EncounterPhase.PrePinFog;
            _ui.PassButton.interactable = !complete && phase == EncounterPhase.Pass;
            _ui.ToPlayPhaseButton.interactable = !complete && phase is EncounterPhase.Discard or EncounterPhase.PrePinFog or EncounterPhase.Pass;
            _ui.SubmitButton.interactable = !complete && phase == EncounterPhase.PlayToSlots;
            _ui.NextQuotaButton.interactable = !complete && phase == EncounterPhase.ResolveQuota;
        }

        private void SetMessage(string message)
        {
            _lastMessage = message;
            if (_ui != null)
            {
                _ui.MessageText.text = message;
            }
        }
    }
}

using PasserCard.Cards;
using PasserCard.Encounter;
using PasserCard.Run;
using PasserCard.UI;
using UnityEngine;

namespace PasserCard.Core
{
    /// <summary>
    /// Scene entry: creates encounter session and optional UI.
    /// </summary>
    public sealed class GameBootstrap : MonoBehaviour
    {
        [SerializeField] private int startingSoulCoins = 20;
        [SerializeField] private int guardianTargetScore = 120;
        [SerializeField] private bool startEncounterOnPlay = true;
        [SerializeField] private bool useEncounterUI = true;

        private EncounterSession? _session;

        public EncounterSession? Session => _session;

        private void Start()
        {
            if (!startEncounterOnPlay)
            {
                return;
            }

            StartNewEncounter();
        }

        [ContextMenu("Start New Encounter")]
        public void StartNewEncounter()
        {
            _session = CreateSession();
            _session.StartEncounter();

            if (useEncounterUI)
            {
                var ui = GetComponent<EncounterUIController>();
                if (ui == null)
                {
                    ui = gameObject.AddComponent<EncounterUIController>();
                }

                ui.Bind(_session);
            }

            Debug.Log($"[PasserCard] Encounter started. Target={guardianTargetScore}, SoulCoins={_session.Wallet.Balance}");
        }

        private EncounterSession CreateSession()
        {
            var config = new EncounterConfig
            {
                TargetScore = guardianTargetScore,
                MistFogSlots = 2
            };

            var wallet = new SoulCoinWallet(startingSoulCoins);
            var deck = PlayingCardFactory.CreateStandardDeck(dualRank: true, random: new System.Random());
            return new EncounterSession(config, deck, wallet, new System.Random());
        }
    }
}

