    if (card != null)
    {
        var sprite = BalatroSpriteLibrary.GetCardSprite(card);
        if (sprite != null)
        {
            image.sprite = sprite;
            image.type = Image.Type.Simple;
            image.preserveAspect = true;
            image.color = Color.white;
            if (text != null)
            {
                text.text = fog ? "雾" : string.Empty;
                text.fontSize = 14;
                text.alignment = TextAnchor.UpperLeft;
                text.color = new Color(1f, 1f, 1f, 0.85f);
            }

            return;
        }
    }

    if (fog && card == null && BalatroSpriteLibrary.CardBack != null)
    {
        image.sprite = BalatroSpriteLibrary.CardBack;
        image.type = Image.Type.Simple;
        image.preserveAspect = true;
        image.color = new Color(0.55f, 0.58f, 0.65f, 1f);
        if (text != null)
