        image.preserveAspect = true;
        image.color = selected ? new Color(1f, 0.92f, 0.65f, 1f) : Color.white;

        if (card.CornerA != card.CornerB)
        {
            text.text = card.IsFlipped ? "B" : "A";
            text.fontSize = 14;
            text.alignment = TextAnchor.LowerRight;
            text.color = new Color(0.15f, 0.15f, 0.2f, 0.95f);
